args.command:
$excelPath = "D:\Users\Djmanny\.gemini\tmp\project\EIA Document.xlsx"
try {
    $excel = New-Object -ComObject Excel.Application
    $excel.Visible = $false
    $workbook = $excel.Workbooks.Open($excelPath)
    $sheet = $workbook.Sheets.Item(1)
    $range = $sheet.UsedRange
    $rows = $range.Rows.Count
    $cols = $range.Columns.Count

    for ($r = 1; $r -le $rows; $r++) {
        $line = ""
        for ($c = 1; $c -le $cols; $c++) {
            $line += "$($sheet.Cells.Item($r, $c).Text) | "
        }
        Write-Output $line
    }

    $workbook.Close($false)
    $excel.Quit()
} catch {
    Write-Output "Error: $($_.Exception.Message)"
}

$excelPath = "D:\Users\Djmanny\.gemini\tmp\project\EIA Document.xlsx"
try {
    $excel = New-Object -ComObject Excel.Application
    $excel.Visible = $false
    $workbook = $excel.Workbooks.Open($excelPath)

    # List all sheet names
    $sheets = foreach ($s in $workbook.Sheets) { $s.Name }
    Write-Output "Available Sheets: $($sheets -join ', ')"

    # Try to find 'summary' sheet (case-insensitive)
    $summarySheet = $workbook.Sheets | Where-Object { $_.Name -like "*summary*" }

    if ($summarySheet) {
        Write-Output "Reading Sheet: $($summarySheet.Name)"
        $range = $summarySheet.UsedRange
        $rows = $range.Rows.Count
        $cols = $range.Columns.Count

        for ($r = 1; $r -le $rows; $r++) {
            $line = ""
            for ($c = 1; $c -le $cols; $c++) {
                $line += "$($summarySheet.Cells.Item($r, $c).Text) | "
            }
            Write-Output $line
        }
    } else {
        Write-Output "Error: 'summary' sheet not found."
    }

    $workbook.Close($false)
    $excel.Quit()
} catch {
    Write-Output "Error: $($_.Exception.Message)"
}
